// Get the HTML from ScrapingBee
const html = $input.first().json.data;

// Helper functions for extraction
const extractText = (pattern, defaultValue = '') => {
  const match = html.match(pattern);
  return match ? match[1].trim() : defaultValue;
};

const extractAll = (pattern) => {
  const matches = [];
  let match;
  const regex = new RegExp(pattern, 'gi');
  while ((match = regex.exec(html)) !== null) {
    matches.push(match[1].trim());
  }
  return matches;
};

// Extract comprehensive structure
const structure = {
  hero: {
    title: extractText(/<h1[^>]*>(.*?)<\/h1>/i, 'Welcome to Our Product'),
    subtitle: extractText(/<h2[^>]*>(.*?)<\/h2>/i, 'The best solution for your needs'),
    cta: extractText(/<button[^>]*>(.*?)<\/button>/i, 'Get Started'),
  },

  headings: {
    h1: extractAll(/<h1[^>]*>(.*?)<\/h1>/gi),
    h2: extractAll(/<h2[^>]*>(.*?)<\/h2>/gi),
    h3: extractAll(/<h3[^>]*>(.*?)<\/h3>/gi),
  },

  // Count sections
  sectionCount: (html.match(/<section/gi) || []).length || 3,

  // Extract CTAs
  buttons: extractAll(/<button[^>]*>(.*?)<\/button>/gi).slice(0, 5),

  // Check for components
  hasNavigation: html.includes('<nav') || html.toLowerCase().includes('navigation') || html.toLowerCase().includes('menu'),
  hasHero: html.match(/<h1[^>]*>/i) !== null,
  hasFeatures: html.toLowerCase().includes('feature') || html.toLowerCase().includes('benefit'),
  hasFooter: html.includes('<footer'),
  hasPricing: html.toLowerCase().includes('pricing') || html.toLowerCase().includes('plan'),
  hasTestimonial: html.toLowerCase().includes('testimonial') || html.toLowerCase().includes('review'),
  hasCTA: html.toLowerCase().includes('call to action') || html.match(/<button/gi)?.length > 2,

  // Page complexity
  pageLength: html.length,
  divCount: (html.match(/<div/gi) || []).length
};

// Extract colors
const colorMatches = html.match(/#[0-9A-Fa-f]{6}|#[0-9A-Fa-f]{3}|rgb\([^)]+\)|rgba\([^)]+\)/gi) || [];
const uniqueColors = [...new Set(colorMatches)].slice(0, 10);

// Typography hints
const typography = {
  hasBold: html.includes('<strong>') || html.includes('<b>'),
  hasItalic: html.includes('<em>') || html.includes('<i>'),
  fonts: extractAll(/font-family:\s*([^;}"]+)/gi).slice(0, 5)
};

// Images
const images = extractAll(/<img[^>]*src=["']([^"']+)["']/gi).slice(0, 5);

return {
  json: {
    structure,
    colors: uniqueColors,
    typography,
    images,
    analyzedAt: new Date().toISOString()
  }
};

// Get all items from merge
const items = $input.all();

// Initialize variables
let analysis = null;
let brand = null;
let competitorUrl = null;
let userEmail = null;

// Extract data from merged items
items.forEach(item => {
  if (item.json.structure) {
    // This is the analysis data
    analysis = {
      structure: item.json.structure,
      colors: item.json.colors || [],
      typography: item.json.typography || {},
      images: item.json.images || [],
      analyzedAt: item.json.analyzedAt
    };
  }

  if (item.json.brandGuidelines) {
    // This is the brand data
    brand = item.json.brandGuidelines;
    competitorUrl = item.json.competitor_url;
    userEmail = item.json.user_email;
  }
});

// If data wasn't split properly, try alternative extraction
if (!analysis || !brand) {
  // Check if everything is in one item
  const firstItem = items[0].json;

  if (firstItem.structure && firstItem.brandGuidelines) {
    analysis = {
      structure: firstItem.structure,
      colors: firstItem.colors || [],
      typography: firstItem.typography || {},
      images: firstItem.images || [],
      analyzedAt: firstItem.analyzedAt
    };
    brand = firstItem.brandGuidelines;
    competitorUrl = firstItem.competitor_url;
    userEmail = firstItem.user_email;
  }
}

// Create clean, structured output
const formattedData = {
  competitor: {
    url: competitorUrl,
    analysis: {
      pageStructure: {
        hero: analysis.structure.hero,
        headings: {
          h1Count: analysis.structure.headings.h1.length,
          h2Count: analysis.structure.headings.h2.length,
          h3Count: analysis.structure.headings.h3.length,
          h3List: analysis.structure.headings.h3.slice(0, 10)
        },
        sections: {
          total: analysis.structure.sectionCount,
          hasNavigation: analysis.structure.hasNavigation,
          hasHero: analysis.structure.hasHero,
          hasFeatures: analysis.structure.hasFeatures,
          hasFooter: analysis.structure.hasFooter,
          hasPricing: analysis.structure.hasPricing,
          hasTestimonial: analysis.structure.hasTestimonial,
          hasCTA: analysis.structure.hasCTA
        },
        buttons: analysis.structure.buttons,
        complexity: {
          pageLength: analysis.structure.pageLength,
          divCount: analysis.structure.divCount
        }
      },
      colors: analysis.colors,
      typography: analysis.typography,
      images: analysis.images,
      analyzedAt: analysis.analyzedAt
    }
  }

};

// Return formatted data
return {
  json: formattedData
};

