// Helper function to strip HTML tags
function stripHtml(text) {
  if (!text) return '';
  return text
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<[^>]*>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .trim();
}

// Helper function to format color palette
function formatColors(colorArray) {
  const colorNames = {
    '#f0f0f0': 'Light Gray',
    '#555': 'Dark Gray',
    '#ffffff': 'White',
    '#007cba': 'Primary Blue',
    '#006ba1': 'Secondary Blue',
    '#005a87': 'Deep Blue',
    '#7a00df': 'Purple/Accent',
    '#eee': 'Light Gray Alt',
    '#313131': 'Charcoal',
    '#00d084': 'Bright Teal/Green'
  };

  if (!colorArray || colorArray.length === 0) return 'Not specified';

  return colorArray
    .filter(color => color && color.trim())
    .map((color, idx) => {
      const cleanColor = color.replace(/[`]/g, '').trim();
      return `${idx + 1}. ${colorNames[cleanColor] || 'Custom Color'}: ${cleanColor}`;
    })
    .join('\n');
}

// Helper function to format images with deduplication
function formatImages(imageArray) {
  if (!imageArray || imageArray.length === 0) return 'No images found';

  const imageMap = {};

  imageArray.forEach((img) => {
    if (!img) return;
    const fileName = img.split('/').pop().split('?')[0];

    if (!imageMap[fileName]) {
      imageMap[fileName] = {
        url: img,
        count: 0
      };
    }
    imageMap[fileName].count++;
  });

  return Object.values(imageMap)
    .map((img, idx) => {
      const countText = img.count > 1 ? ` (used ${img.count} times)` : '';
      return `${idx + 1}. ${img.url}${countText}`;
    })
    .join('\n');
}

